145	/// State machine for reading a numeric literal byte-by-byte from a file.
146	/// C: `typedef struct { FILE *f; int c; int n; char buff[L_MAXLENNUM+1]; } RN`.
147	struct ReadNumState {
148	    /// Current look-ahead byte, or `EOF_SENTINEL`.
149	    current: i32,
150	    /// Number of bytes accumulated in `buf`.
151	    count: usize,
152	    /// Accumulated characters of the numeral (NUL-terminated on finalise).
153	    buf: [u8; L_MAX_LEN_NUM + 1],
154	}
155	
156	impl ReadNumState {
157	    fn new(first_byte: i32) -> Self {
158	        ReadNumState {
159	            current: first_byte,
160	            count: 0,
161	            buf: [0u8; L_MAX_LEN_NUM + 1],
162	        }
163	    }
164	
165	    /// Save current char to `buf` and read the next byte from `file`.
166	    /// Returns `false` if the buffer is full (numeral too long). C: `nextc`.
167	    fn advance(&mut self, file: &mut dyn LuaFileOps) -> bool {
168	        // C: if (rn->n >= L_MAXLENNUM) { rn->buff[0] = '\0'; return 0; }
169	        if self.count >= L_MAX_LEN_NUM {
170	            self.buf[0] = 0;
171	            return false;
172	        }
173	        self.buf[self.count] = self.current as u8;
174	        self.count += 1;
175	        self.current = file.read_byte();
176	        true
177	    }
178	
179	    /// Accept current char if it equals either byte in `set`. C: `test2`.
180	    fn try2(&mut self, file: &mut dyn LuaFileOps, set: [u8; 2]) -> bool {
181	        // C: if (rn->c == set[0] || rn->c == set[1]) return nextc(rn);
182	        if self.current == set[0] as i32 || self.current == set[1] as i32 {
183	            self.advance(file)
184	        } else {
185	            false
186	        }
187	    }
188	
189	    /// Consume a run of (hex)digits; return the count. C: `readdigits`.
190	    fn read_digits(&mut self, file: &mut dyn LuaFileOps, hex: bool) -> usize {
191	        // C: while ((hex ? isxdigit(rn->c) : isdigit(rn->c)) && nextc(rn)) count++;
192	        let mut count = 0usize;
193	        loop {
194	            let is_digit = if hex {
195	                (self.current as u8).is_ascii_hexdigit()
196	            } else {
197	                (self.current as u8).is_ascii_digit()
198	            };
199	            if !is_digit || self.current == EOF_SENTINEL {
200	                break;
201	            }
202	            if !self.advance(file) {
203	                break;
204	            }
205	            count += 1;
206	        }
207	        count
208	    }
209	
210	    /// Return the accumulated bytes (without the NUL terminator).
211	    fn as_bytes(&self) -> &[u8] {
212	        &self.buf[..self.count]
213	    }
214	}
