314	/// Push popen/system exit-status results per `luaL_execresult`.
315	///
316	/// C: `if (stat == 0) { lua_pushboolean(L,1); return 1; }
317	///     else { luaL_pushfail; pushlstring("exit"|"signal"); pushinteger(stat); return 3; }`
318	///
319	/// TODO(port): POSIX `WIFEXITED`/`WTERMSIG` macros not available on all platforms;
320	/// this stub always treats non-zero stat as an exit code.
321	fn exec_result(state: &mut LuaState, stat: i32) -> Result<usize, LuaError> {
322	    if stat == 0 {
323	        state.push(LuaValue::Bool(true));
324	        Ok(1)
325	    } else {
326	        state.push(LuaValue::Bool(false));
327	        // TODO(port): distinguish exit vs signal via POSIX macros
328	        state.push_string(b"exit");
329	        state.push(LuaValue::Int(stat as i64));
330	        Ok(3)
331	    }
332	}
