345	/// Return the open file handle for argument 1; error if closed. C: `tofile`.
346	///
347	/// TODO(port): borrow split — cannot return `&mut dyn LuaFileOps` while the caller
348	/// also holds `&mut LuaState`. Phase B fix: `RefCell<Box<dyn LuaFileOps>>` inside
349	/// `LStream`, or restructure all callers to use a `StackIdx` file reference.
350	fn tofile(state: &mut LuaState) -> Result<&mut dyn LuaFileOps, LuaError> {
351	    let p = get_lstream(state)?;
352	    // C: if (isclosed(p)) luaL_error(L, "attempt to use a closed file");
353	    if p.is_closed() {
354	        return Err(LuaError::runtime(format_args!(
355	            "attempt to use a closed file"
356	        )));
357	    }
358	    // C: lua_assert(p->f);
359	    debug_assert!(p.file.is_some());
360	    Ok(p.file.as_mut().expect("open stream has no file handle").as_mut())
361	}
