442	/// Refuse to close a standard-stream handle. C: `io_noclose`.
443	fn io_noclose(state: &mut LuaState) -> Result<usize, LuaError> {
444	    // C: p->closef = &io_noclose;  /* keep file opened */
445	    // C: luaL_pushfail(L); lua_pushliteral(L, "cannot close standard file"); return 2;
446	    let p = get_lstream(state)?;
447	    p.close_fn = Some(io_noclose); // reinstall to keep the handle alive
448	    state.push(LuaValue::Bool(false));
449	    state.push_string(b"cannot close standard file");
450	    Ok(2)
451	}
