720	/// Test for EOF: push `""` and return `true` if not at EOF. C: `test_eof`.
721	fn test_eof(
722	    state: &mut LuaState,
723	    file: &mut dyn LuaFileOps,
724	) -> Result<bool, LuaError> {
725	    // C: int c = getc(f); ungetc(c, f); lua_pushliteral(L, ""); return (c != EOF);
726	    let c = file.read_byte();
727	    if c != EOF_SENTINEL {
728	        file.unread_byte(c);
729	    }
730	    state.push_string(b"");
731	    Ok(c != EOF_SENTINEL)
732	}
