822	/// Dispatch one or more read formats; push results. C: `g_read(L, f, first)`.
823	///
824	/// TODO(port): borrow split — `file` is `&mut dyn LuaFileOps` extracted from a
825	/// `LuaUserData` that lives inside `state`. Phase B must restructure so the file
826	/// is accessed through the stack index rather than a raw borrow.
827	fn g_read(
828	    state: &mut LuaState,
829	    file: &mut dyn LuaFileOps,
830	    first: i32,
831	) -> Result<usize, LuaError> {
832	    // C: int nargs = lua_gettop(L) - 1;
833	    let nargs = state.top_idx().get() as i32 - 1;
834	    let mut n = first;
835	    let mut success = true;
836	
837	    // C: clearerr(f);
838	    file.clear_error();
839	
840	    if nargs == 0 {
841	        // C: success = read_line(L, f, 1); n = first + 1;
842	        success = read_line(state, file, true)?;
843	        n = first + 1;
844	    } else {
845	        // C: luaL_checkstack(L, nargs+LUA_MINSTACK, "too many arguments");
846	        state.ensure_stack((nargs as i32) + 20, "too many arguments")?;
847	        let mut remaining = nargs;
848	        while remaining > 0 && success {
849	            // C: if (lua_type(L, n) == LUA_TNUMBER)
850	            if state.type_at(n) == LuaType::Number {
851	                // C: size_t l = (size_t)luaL_checkinteger(L, n);
852	                let l = state.check_arg_integer(n)? as usize;
853	                success = if l == 0 {
854	                    test_eof(state, file)?
855	                } else {
856	                    read_chars(state, file, l)?
857	                };
858	            } else {
859	                // C: const char *p = luaL_checkstring(L, n);
860	                // C: if (*p == '*') p++;  /* skip optional '*' (compat) */
861	                let s: Vec<u8> = state.check_arg_string(n)?;
862	                let p: &[u8] = if s.first() == Some(&b'*') { &s[1..] } else { &s[..] };
863	                match p.first() {
864	                    // C: case 'n': success = read_number(L, f); break;
865	                    Some(&b'n') => {
866	                        success = read_number(state, file)?;
867	                    }
868	                    // C: case 'l': success = read_line(L, f, 1); break;
869	                    Some(&b'l') => {
870	                        success = read_line(state, file, true)?;
871	                    }
872	                    // C: case 'L': success = read_line(L, f, 0); break;
873	                    Some(&b'L') => {
874	                        success = read_line(state, file, false)?;
875	                    }
876	                    // C: case 'a': read_all(L, f); success = 1; break;
877	                    Some(&b'a') => {
878	                        read_all(state, file)?;
879	                        success = true;
880	                    }
881	                    _ => {
882	                        return Err(LuaError::arg_error(n, "invalid format"));
883	                    }
884	                }
885	            }
886	            n += 1;
887	            remaining -= 1;
888	        }
889	    }
890	
891	    // C: if (ferror(f)) return luaL_fileresult(L, 0, NULL);
892	    if file.has_error() {
893	        return file_result(
894	            state,
895	            false,
896	            None,
897	            io::Error::new(io::ErrorKind::Other, "file read error"),
898	        );
899	    }
900	
901	    // C: if (!success) { lua_pop(L, 1); luaL_pushfail(L); }
902	    if !success {
903	        state.pop_n(1);
904	        state.push(LuaValue::Bool(false));
905	    }
906	
907	    // C: return n - first;
908	    Ok((n - first) as usize)
909	}
